import chess

def to64(fen):
    out=[]
    for row in fen.split(' ')[0].split('/'):
        for ch in row:
            if ch.isdigit():
                out.append('.'*int(ch))
            else:
                out.append(ch)
    s=''.join(out)
    assert len(s)==64, (len(s), s)
    return s

def compress_row(row):
    res=[]; cnt=0
    for ch in row:
        if ch=='.':
            cnt+=1
        else:
            if cnt:
                res.append(str(cnt)); cnt=0
            res.append(ch)
    if cnt: res.append(str(cnt))
    return ''.join(res)

def from64(s):
    return '/'.join(compress_row(s[i*8:i*8+8]) for i in range(8))

def square_index(sq):
    if sq == '-':
        return None
    file='abcdefgh'.index(sq[0])
    rank=int(sq[1])
    return (8-rank)*8 + file

def gen_pseudo(fen):
    b=chess.Board(fen)
    parts=fen.split(' ')
    board, side, castle, ep = parts[0], parts[1], parts[2], parts[3]
    s=to64(fen)
    moves=[]

    def add_board(ns, castling=castle, ep_out='-'):
        moves.append(from64(''.join(ns)) + f' b {castling} {ep_out} 0 0')

    # Pawns (white moves from higher rank toward lower indices)
    for i,ch in enumerate(s):
        if ch != 'P':
            continue
        r=i//8; f=i%8
        # single step
        if r > 0 and s[i-8] == '.':
            if r == 1:
                ns=list(s); ns[i]='.'; ns[i-8]='Q'; add_board(ns)
            else:
                ns=list(s); ns[i]='.'; ns[i-8]='P'; add_board(ns)
