                if r == 6 and s[i-16] == '.':
                    ns=list(s); ns[i]='.'; ns[i-16]='P'
                    ep_sq = 'abcdefgh'[f] + '3'
                    add_board(ns, ep_out=ep_sq)
        # captures
        for df in (-1, 1):
            nf = f + df
            if not (0 <= nf < 8):
                continue
            j = i - 8 + df
            if j < 0:
                continue
            target = s[j]
            if target != '.' and target.islower():
                if r == 1:
                    ns=list(s); ns[i]='.'; ns[j]='Q'; add_board(ns)
                else:
